/**
 * Tests that resume text extracted from an ATS-exported PDF
 * (generated by the application's own Puppeteer renderer) is
 * correctly parsed back into structured resume data.
 *
 * The ATS template uses:
 *   <h2>SECTION HEADING</h2>          → "SECTION HEADING" on its own line
 *   <h3>Role, Company</h3>            → "Role, Company" (comma-separated)
 *   <p class="ats-item__meta">Date</p> → "Dec 2022 - Present"
 *   <ul><li>Bullet text</li></ul>      → Bullet text (no prefix; CSS-drawn markers)
 *   <p>Skill1, Skill2, ...</p>         → comma-separated skills
 */
const assert = require('node:assert/strict');
const test = require('node:test');
const { mapParsedResume, parseResumeText } = require('../dist/index.js');

function mapResume(text) {
  return mapParsedResume(parseResumeText(text));
}

// ──────────────────────────────────────────────────────────────────────────────
// Test 1: ATS classic template with comma-separated "Role, Company" headers
// ──────────────────────────────────────────────────────────────────────────────
test('ATS PDF roundtrip: classic template with comma-separated Role, Company headers', () => {
  const atsText = `
Chandan Kumar
cks011992@gmail.com | +91-9307003382 | Pune, MH 411057 | https://www.linkedin.com/in/chandankumar007

SUMMARY
10+ years of experience in the IT industry with expertise in full-stack development, agile planning, and driving innovation across enterprise platforms.

SKILLS
JavaScript, React, Node.js, TypeScript, Angular, HTML, CSS, AWS, Docker, Git, Agile methodologies, CI/CD, MongoDB, PostgreSQL, Redis, Microservices, REST APIs, GraphQL, Kubernetes

EXPERIENCE
AVP - Full Stack Engineer, Citi Corp
Dec 2022 - Present
Led cross-functional teams to deliver enterprise-grade applications
Architected scalable microservices using Node.js and React
Improved release quality through CI guardrails

Senior Technology Consultant, Ernst & Young
Oct 2021 - Dec 2022
Engineered reusable template architecture for resume exports
Reduced frontend effort by 60% across teams

Senior Software Developer, One Network Enterprises
Sep 2020 - Sep 2021
Managed complete development lifecycle from UX planning to deployment
Improved production reliability with better observability

Lead UI Developer, Infosys Ltd
Jul 2014 - Aug 2020
Directed end-to-end UI delivery for FINACLE
Standardized coding patterns for maintainability

EDUCATION
Master of Computer Applications
Savitribai Phule Pune University
2012 - 2014

Bachelor of Computer Applications
University of Pune
2009 - 2012

Higher Secondary Certificate
D.A.V Public School
2006 - 2008

CERTIFICATIONS
AWS Certified Solutions Architect
Amazon Web Services | 2023
`;

  const mapped = mapResume(atsText);

  // ── Contact ──
  assert.equal(mapped.contact?.fullName, 'Chandan Kumar');
  assert.equal(mapped.contact?.email, 'cks011992@gmail.com');

  // ── Title should not be a section heading ──
  assert.notEqual((mapped.title || '').toLowerCase(), 'skills');
  assert.notEqual((mapped.title || '').toLowerCase(), 'experience');

  // ── Summary ──
  assert.ok(mapped.summary.length > 20, `Summary too short: "${mapped.summary}"`);
  assert.ok(mapped.summary.includes('10+ years'), `Summary missing key content: "${mapped.summary}"`);

  // ── Skills: should extract most comma-separated items ──
  assert.ok(mapped.skills.length >= 10, `Expected >= 10 skills, got ${mapped.skills.length}: ${JSON.stringify(mapped.skills)}`);
  assert.ok(mapped.skills.some((s) => s.toLowerCase().includes('javascript')), 'Missing JavaScript');
  assert.ok(mapped.skills.some((s) => s.toLowerCase().includes('react')), 'Missing React');
  assert.ok(mapped.skills.some((s) => s.toLowerCase().includes('typescript')), 'Missing TypeScript');
  assert.ok(mapped.skills.some((s) => s.toLowerCase().includes('node')), 'Missing Node.js');
  assert.ok(mapped.skills.some((s) => s.toLowerCase().includes('docker')), 'Missing Docker');
  assert.ok(mapped.skills.some((s) => s.toLowerCase().includes('kubernetes')), 'Missing Kubernetes');

  // ── Experience: 4 entries with correct role/company splits ──
  assert.equal(mapped.experience.length, 4, `Expected 4 experiences, got ${mapped.experience.length}: ${JSON.stringify(mapped.experience.map((e) => `${e.role} @ ${e.company}`))}`);

  const citi = mapped.experience.find((e) => e.company.toLowerCase().includes('citi'));
  assert.ok(citi, 'Missing Citi Corp experience');
  assert.ok(citi.role.toLowerCase().includes('avp') || citi.role.toLowerCase().includes('full stack'), `Citi role wrong: "${citi.role}"`);
  assert.equal(citi.startDate, 'Dec 2022');
  assert.equal(citi.endDate, 'Present');
  assert.ok(citi.highlights.length >= 1, 'Citi should have highlights');

  const ey = mapped.experience.find((e) => e.company.toLowerCase().includes('ernst'));
  assert.ok(ey, 'Missing Ernst & Young experience');
  assert.ok(ey.role.toLowerCase().includes('consultant'), `EY role wrong: "${ey.role}"`);
  assert.equal(ey.startDate, 'Oct 2021');
  assert.equal(ey.endDate, 'Dec 2022');

  const oneNetwork = mapped.experience.find((e) => e.company.toLowerCase().includes('one network'));
  assert.ok(oneNetwork, 'Missing One Network experience');
  assert.ok(oneNetwork.role.toLowerCase().includes('developer'), `One Network role wrong: "${oneNetwork.role}"`);

  const infosys = mapped.experience.find((e) => e.company.toLowerCase().includes('infosys'));
  assert.ok(infosys, 'Missing Infosys experience');
  assert.ok(infosys.role.toLowerCase().includes('lead') || infosys.role.toLowerCase().includes('developer'), `Infosys role wrong: "${infosys.role}"`);

  // ── Education: 3 entries ──
  assert.ok(mapped.education.length >= 2, `Expected >= 2 education entries, got ${mapped.education.length}`);
  assert.ok(mapped.education.some((e) => e.degree.toLowerCase().includes('master')), 'Missing MCA degree');
  assert.ok(mapped.education.some((e) => e.degree.toLowerCase().includes('bachelor')), 'Missing BCA degree');

  // ── Certifications ──
  assert.ok(mapped.certifications.length >= 1, `Expected >= 1 certification, got ${mapped.certifications.length}`);
  assert.ok(mapped.certifications.some((c) => c.name.toLowerCase().includes('aws')), 'Missing AWS certification');

  // ── Role level should NOT be FRESHER for 10+ years experience ──
  assert.notEqual(mapped.roleLevel, 'FRESHER', `Role level should not be FRESHER for 10+ years exp`);
});

// ──────────────────────────────────────────────────────────────────────────────
// Test 2: ATS modern template with pipe-separated "Role | Company" headers
// ──────────────────────────────────────────────────────────────────────────────
test('ATS PDF roundtrip: modern template with pipe-separated Role | Company headers', () => {
  const atsText = `
Alex Rivera
alex@example.com | +1-555-0100 | San Francisco, CA

SUMMARY
Platform engineer delivering reliable backend systems with 8 years of experience.

SKILLS
Python, Go, Kubernetes, Terraform, AWS, GCP, Docker, PostgreSQL, Redis, Kafka

EXPERIENCE
Senior Platform Engineer | CloudScale Inc
Jan 2021 - Present
Built auto-scaling platform serving 10M requests/day
Reduced infrastructure costs by 40% through optimization

Backend Engineer | DataFlow Systems
Mar 2018 - Dec 2020
Designed event-driven architecture processing 50K events/sec
Led migration from monolith to microservices

Junior Developer | StartupXYZ
Jun 2015 - Feb 2018
Built REST APIs for mobile application backend
Implemented CI/CD pipeline using Jenkins

EDUCATION
B.S. Computer Science
Stanford University
2011 - 2015
`;

  const mapped = mapResume(atsText);

  assert.equal(mapped.experience.length, 3, `Expected 3 experiences, got ${mapped.experience.length}`);
  assert.ok(mapped.experience.some((e) => e.company.toLowerCase().includes('cloudscale')));
  assert.ok(mapped.experience.some((e) => e.company.toLowerCase().includes('dataflow')));
  assert.ok(mapped.experience.some((e) => e.role.toLowerCase().includes('senior platform')));
  assert.ok(mapped.skills.length >= 5);
  assert.ok(mapped.education.length >= 1);
});

// ──────────────────────────────────────────────────────────────────────────────
// Test 3: ATS template with bullet-prefixed highlights (pdf-parse extracts
// unicode bullets which normalizeText converts to "- " prefixes)
// ──────────────────────────────────────────────────────────────────────────────
test('ATS PDF roundtrip: highlights without bullet prefixes still map correctly', () => {
  const atsText = `
Jane Smith
jane@example.com

EXPERIENCE
Software Architect, TechNova Solutions
Jan 2020 - Present
Designed distributed systems handling 1M concurrent users
Mentored team of 12 engineers on clean architecture principles
Reduced system downtime by 99.5% through redundancy improvements

Full Stack Developer, WebCraft Digital
Jun 2016 - Dec 2019
Built real-time collaboration features using WebSockets
Implemented automated testing pipeline reducing bugs by 60%
`;

  const mapped = mapResume(atsText);
  assert.equal(mapped.experience.length, 2);

  const techNova = mapped.experience.find((e) => e.company.toLowerCase().includes('technova'));
  assert.ok(techNova, 'Missing TechNova experience');
  assert.ok(techNova.highlights.length >= 2, `TechNova should have >= 2 highlights, got ${techNova.highlights.length}`);
  assert.ok(techNova.role.toLowerCase().includes('architect'), `TechNova role wrong: "${techNova.role}"`);
});

// ──────────────────────────────────────────────────────────────────────────────
// Test 4: splitRoleCompany correctly handles comma-separated role/company
// ──────────────────────────────────────────────────────────────────────────────
test('ATS format: comma-separated role/company splits correctly', () => {
  const mapped = mapResume(`
Experience
AVP - Full Stack Engineer, Citi Corp
Dec 2022 - Present
Led cross-functional delivery
`);

  assert.equal(mapped.experience.length, 1);
  const entry = mapped.experience[0];
  assert.ok(entry.role.toLowerCase().includes('avp'), `Role should include AVP: "${entry.role}"`);
  assert.ok(entry.role.toLowerCase().includes('full stack') || entry.role.toLowerCase().includes('engineer'),
    `Role should include Full Stack/Engineer: "${entry.role}"`);
  assert.ok(entry.company.toLowerCase().includes('citi'), `Company should be Citi Corp: "${entry.company}"`);
});

// ──────────────────────────────────────────────────────────────────────────────
// Test 5: Skills with dots (Node.js, Vue.js) are preserved
// ──────────────────────────────────────────────────────────────────────────────
test('ATS format: skills with dots like Node.js are not filtered out', () => {
  const mapped = mapResume(`
SKILLS
JavaScript, React, Node.js, Vue.js, TypeScript, ASP.NET, C#, Docker
`);

  assert.ok(mapped.skills.some((s) => s.toLowerCase().includes('node')), `Missing Node.js: ${JSON.stringify(mapped.skills)}`);
  assert.ok(mapped.skills.some((s) => s.toLowerCase().includes('vue')), `Missing Vue.js: ${JSON.stringify(mapped.skills)}`);
  assert.ok(mapped.skills.some((s) => s.toLowerCase().includes('asp')), `Missing ASP.NET: ${JSON.stringify(mapped.skills)}`);
});

